void ssd1306SendCommand(uint8_t cmd) {
    uint8_t buf[] = {0x00, cmd};
    i2c_write_blocking(SSD1306_I2C, SSD1306_ADDRESS, buf, 2, false);
}

void ssd1306SendCommandBuffer(uint8_t *inbuf, int len) {
    i2c_write_blocking(SSD1306_I2C, SSD1306_ADDRESS, inbuf, len, false);
}

void ssd1306_init() {
    uint8_t init_cmds[] = {
        0x00,                          // Start of command stream
        SSD1306_DISPLAYOFF,            // Display off
        SSD1306_SETMULTIPLEX, 0x3F,
        SSD1306_SETDISPLAYOFFSET, 0x00,
        SSD1306_SETSTARTLINE,          // 0x40
        SSD1306_SEGREMAP0,             // Normal direction (change to SSD1306_SEGREMAP127 if mirrored)
        SSD1306_COMSCANINC,            // Normal scan (change to SSD1306_COMSCANDEC if flipped vertically)
        SSD1306_SETCOMPINS, 0x12,
        SSD1306_SETCONTRAST, 0xCF,     // Contrast - you can try 0x7F to 0xFF later
        SSD1306_DISPLAYALLON_RESUME,
        SSD1306_NORMALDISPLAY,
        SSD1306_SETDISPLAYCLOCKDIV, 0x80,
        SSD1306_CHARGEPUMP, 0x14,      // Enable charge pump

        // SSD1309 / CH1116 specific commands
        0xAD, 0x8A,                    // SETDCDC - important for many of these modules

        SSD1306_SETVCOMDETECT, 0x40,

        SSD1306_DISPLAYON,             // Turn display on

        // Memory addressing
        SSD1306_MEMORYMODE, 0x00,      // Horizontal addressing mode (MaplePad expects this)

        // Critical fix for left-edge junk / shift (most common on CH1116/SSD1309)
        SSD1306_COLUMNADDR, 0x02, 0x7F,   // Start column = 2, end = 127

        SSD1306_PAGEADDR, 0, 7         // Pages 0 to 7
    };

    // Handle OLED_FLIP if you have that option enabled
    if (OLED_FLIP) {
        init_cmds[5] = SSD1306_SEGREMAP127;   // indices may need slight adjustment if you count differently
        init_cmds[6] = SSD1306_COMSCANDEC;
    }

    ssd1306SendCommandBuffer(init_cmds, sizeof(init_cmds));

    clearSSD1306();
    updateSSD1306();
}
  
// This copies the entire framebuffer to the display.
void updateSSD1306() {
    i2c_write_blocking(SSD1306_I2C, SSD1306_ADDRESS, _Framebuffer, sizeof(_Framebuffer), false);
}

void clearSSD1306() {
    memset(Framebuffer, 0, SSD1306_FRAMEBUFFER_SIZE);
}

void splashSSD1306(){
    for(int i = 0; i < sizeof(maple_mono); i++){
        if(maple_mono[i])
            setPixelSSD1306( i % 128, i / 128, 1);
    }
    i2c_write_blocking(SSD1306_I2C, SSD1306_ADDRESS, _Framebuffer, sizeof(_Framebuffer), false);
}

// thanks, gpt-4! :D
void setPixelSSD1306(int x, int y, bool on) {
    assert(x >= 0 && x < SSD1306_LCDWIDTH && y >=0 && y < SSD1306_LCDHEIGHT);

    const int BytesPerRow = SSD1306_LCDWIDTH;
    int byte_idx = (y >> 3) * BytesPerRow  +  x;
    uint8_t mask = 1 << (y & 7);

    if (on)
        Framebuffer[byte_idx] |= mask;
    else
        Framebuffer[byte_idx] &= ~mask;
}


